mapper.select:
select a.id, a.slug, a.title, a.description, a.body, a.author_id, a.created_at, a.updated_at ,u.username,u.bio,u.image from article a join user u on a.author_id=u.id
u.username=#{author}
and exists(select 1 from tag t join article_tags at on t.id=at.tag_id where t.name=#{tag} and at.article_id=a.id)
and exists(select 1 from user u2 join user_favorites uf on u2.id=uf.user_id where u2.username=#{favorited} and uf.article_id=a.id)
order by a.created_at desc limit #{limit} offset #{offset}

select * ,u.username as "author.username",u.bio as "author.bio",u.image as "author.image" from article a join user u on a.author_id=u.id
    and exists(select 1 from user_follows uf where uf.follower_id=#{id} and uf.followee_id=a.author_id)
order by a.created_at desc limit #{limit} offset #{offset}
